export default {
  id: 96,
  title: 'Практикум: Микросервисы',
  description: 'Практика построения микросервисов на Go: сервис пользователей, продуктов, API-шлюз, health check, конфигурационный сервис, аутентификация, уведомления и сервис заказов с паттерном Saga.',
  lessons: [
    {
      id: 1,
      title: 'Сервис пользователей',
      type: 'practice',
      difficulty: 'medium',
      description: 'Создай HTTP микросервис для управления пользователями с CRUD операциями, валидацией и JSON API.',
      requirements: [
        'Структура User: ID string (UUID), Name string, Email string, CreatedAt time.Time',
        'POST /users — создание (валидация: name и email обязательны, email уникален)',
        'GET /users — список всех пользователей',
        'GET /users/{id} — один пользователь',
        'PUT /users/{id} — обновление',
        'DELETE /users/{id} — удаление, возвращает 204',
        'In-memory хранилище с sync.RWMutex',
        'Все ответы в JSON, ошибки в формате {"error": "сообщение"}'
      ],
      expectedOutput: 'POST /users: 201 {"id":"uuid","name":"Alice","email":"alice@example.com"}\nGET /users: 200 [{"id":"uuid",...}]\nGET /users/unknown: 404 {"error":"пользователь не найден"}\nDELETE /users/{id}: 204',
      hint: 'Используй crypto/rand или fmt.Sprintf("%x", time.Now().UnixNano()) для генерации ID. Напиши middleware для Content-Type: application/json. Выдели функцию respondJSON и respondError.',
      solution: 'package main\n\nimport (\n    "encoding/json"\n    "fmt"\n    "net/http"\n    "strings"\n    "sync"\n    "time"\n)\n\ntype User struct {\n    ID        string    `json:"id"`\n    Name      string    `json:"name"`\n    Email     string    `json:"email"`\n    CreatedAt time.Time `json:"created_at"`\n}\n\ntype UserStore struct {\n    mu    sync.RWMutex\n    users map[string]*User\n}\n\nfunc NewUserStore() *UserStore {\n    return &UserStore{users: make(map[string]*User)}\n}\n\nfunc generateID() string {\n    return fmt.Sprintf("%x", time.Now().UnixNano())\n}\n\nfunc (s *UserStore) Create(u User) (*User, error) {\n    s.mu.Lock()\n    defer s.mu.Unlock()\n    for _, existing := range s.users {\n        if existing.Email == u.Email {\n            return nil, fmt.Errorf("email уже используется")\n        }\n    }\n    u.ID = generateID()\n    u.CreatedAt = time.Now()\n    s.users[u.ID] = &u\n    return &u, nil\n}\n\nfunc (s *UserStore) GetAll() []*User {\n    s.mu.RLock()\n    defer s.mu.RUnlock()\n    users := make([]*User, 0, len(s.users))\n    for _, u := range s.users {\n        users = append(users, u)\n    }\n    return users\n}\n\nfunc (s *UserStore) GetByID(id string) (*User, bool) {\n    s.mu.RLock()\n    defer s.mu.RUnlock()\n    u, ok := s.users[id]\n    return u, ok\n}\n\nfunc (s *UserStore) Update(id string, updates User) (*User, bool) {\n    s.mu.Lock()\n    defer s.mu.Unlock()\n    u, ok := s.users[id]\n    if !ok {\n        return nil, false\n    }\n    if updates.Name != "" {\n        u.Name = updates.Name\n    }\n    if updates.Email != "" {\n        u.Email = updates.Email\n    }\n    return u, true\n}\n\nfunc (s *UserStore) Delete(id string) bool {\n    s.mu.Lock()\n    defer s.mu.Unlock()\n    if _, ok := s.users[id]; !ok {\n        return false\n    }\n    delete(s.users, id)\n    return true\n}\n\nfunc respondJSON(w http.ResponseWriter, status int, v interface{}) {\n    w.Header().Set("Content-Type", "application/json")\n    w.WriteHeader(status)\n    json.NewEncoder(w).Encode(v)\n}\n\nfunc respondError(w http.ResponseWriter, status int, msg string) {\n    respondJSON(w, status, map[string]string{"error": msg})\n}\n\nfunc main() {\n    store := NewUserStore()\n    mux := http.NewServeMux()\n    mux.HandleFunc("/users", func(w http.ResponseWriter, r *http.Request) {\n        switch r.Method {\n        case http.MethodGet:\n            respondJSON(w, 200, store.GetAll())\n        case http.MethodPost:\n            var u User\n            if err := json.NewDecoder(r.Body).Decode(&u); err != nil {\n                respondError(w, 400, "неверный формат запроса")\n                return\n            }\n            if strings.TrimSpace(u.Name) == "" || strings.TrimSpace(u.Email) == "" {\n                respondError(w, 400, "name и email обязательны")\n                return\n            }\n            created, err := store.Create(u)\n            if err != nil {\n                respondError(w, 409, err.Error())\n                return\n            }\n            respondJSON(w, 201, created)\n        default:\n            respondError(w, 405, "метод не поддерживается")\n        }\n    })\n    mux.HandleFunc("/users/", func(w http.ResponseWriter, r *http.Request) {\n        id := strings.TrimPrefix(r.URL.Path, "/users/")\n        if id == "" {\n            respondError(w, 400, "требуется ID")\n            return\n        }\n        switch r.Method {\n        case http.MethodGet:\n            u, ok := store.GetByID(id)\n            if !ok {\n                respondError(w, 404, "пользователь не найден")\n                return\n            }\n            respondJSON(w, 200, u)\n        case http.MethodPut:\n            var updates User\n            json.NewDecoder(r.Body).Decode(&updates)\n            u, ok := store.Update(id, updates)\n            if !ok {\n                respondError(w, 404, "пользователь не найден")\n                return\n            }\n            respondJSON(w, 200, u)\n        case http.MethodDelete:\n            if !store.Delete(id) {\n                respondError(w, 404, "пользователь не найден")\n                return\n            }\n            w.WriteHeader(204)\n        default:\n            respondError(w, 405, "метод не поддерживается")\n        }\n    })\n    fmt.Println("User Service запущен на :8081")\n    http.ListenAndServe(":8081", mux)\n}',
      explanation: 'Разделение ответственности: UserStore инкапсулирует хранилище, HTTP-обработчики занимаются только HTTP-логикой. respondJSON и respondError — вспомогательные функции избегают дублирования. sync.RWMutex оптимален для read-heavy нагрузки: множество параллельных чтений, редкие записи. Использование /users и /users/ как разных паттернов — особенность стандартного ServeMux.'
    },
    {
      id: 2,
      title: 'Сервис продуктов',
      type: 'practice',
      difficulty: 'medium',
      description: 'Создай микросервис каталога продуктов с поддержкой фильтрации, пагинации и управлением запасами.',
      requirements: [
        'Структура Product: ID string, Name string, Price float64, Category string, Stock int',
        'CRUD эндпоинты: POST/GET /products, GET/PUT/DELETE /products/{id}',
        'GET /products поддерживает query params: category, min_price, max_price, page, limit',
        'PUT /products/{id}/stock — обновление остатков (body: {"delta": -5})',
        'Запрет отрицательных остатков Stock',
        'GET /products/categories — список уникальных категорий'
      ],
      expectedOutput: 'GET /products?category=Electronics&page=1&limit=2:\n  200 [{id:"...",name:"Ноутбук",price:80000,...}]\nPUT /products/{id}/stock {"delta":-100}: 400 {"error":"недостаточно товара"}\nGET /products/categories: ["Electronics","Books","Clothing"]',
      hint: 'r.URL.Query().Get("category") читает query параметры. Для пагинации: skip = (page-1)*limit, take = limit. Функция filterProducts применяет все фильтры последовательно.',
      solution: 'package main\n\nimport (\n    "encoding/json"\n    "fmt"\n    "net/http"\n    "strconv"\n    "strings"\n    "sync"\n    "time"\n)\n\ntype Product struct {\n    ID       string  `json:"id"`\n    Name     string  `json:"name"`\n    Price    float64 `json:"price"`\n    Category string  `json:"category"`\n    Stock    int     `json:"stock"`\n}\n\ntype ProductStore struct {\n    mu       sync.RWMutex\n    products map[string]*Product\n}\n\nfunc NewProductStore() *ProductStore {\n    s := &ProductStore{products: make(map[string]*Product)}\n    for _, p := range []Product{\n        {Name: "Ноутбук", Price: 80000, Category: "Electronics", Stock: 10},\n        {Name: "Телефон", Price: 50000, Category: "Electronics", Stock: 25},\n        {Name: "Книга Go", Price: 1500, Category: "Books", Stock: 100},\n        {Name: "Футболка", Price: 2000, Category: "Clothing", Stock: 50},\n    } {\n        p.ID = fmt.Sprintf("%x", time.Now().UnixNano())\n        time.Sleep(time.Nanosecond)\n        s.products[p.ID] = &p\n    }\n    return s\n}\n\nfunc (s *ProductStore) Filter(category string, minPrice, maxPrice float64, page, limit int) []*Product {\n    s.mu.RLock()\n    defer s.mu.RUnlock()\n    var result []*Product\n    for _, p := range s.products {\n        if category != "" && p.Category != category {\n            continue\n        }\n        if minPrice > 0 && p.Price < minPrice {\n            continue\n        }\n        if maxPrice > 0 && p.Price > maxPrice {\n            continue\n        }\n        result = append(result, p)\n    }\n    if limit <= 0 {\n        limit = 10\n    }\n    if page <= 0 {\n        page = 1\n    }\n    skip := (page - 1) * limit\n    if skip >= len(result) {\n        return []*Product{}\n    }\n    end := skip + limit\n    if end > len(result) {\n        end = len(result)\n    }\n    return result[skip:end]\n}\n\nfunc (s *ProductStore) UpdateStock(id string, delta int) (*Product, error) {\n    s.mu.Lock()\n    defer s.mu.Unlock()\n    p, ok := s.products[id]\n    if !ok {\n        return nil, fmt.Errorf("продукт не найден")\n    }\n    if p.Stock+delta < 0 {\n        return nil, fmt.Errorf("недостаточно товара")\n    }\n    p.Stock += delta\n    return p, nil\n}\n\nfunc (s *ProductStore) Categories() []string {\n    s.mu.RLock()\n    defer s.mu.RUnlock()\n    seen := make(map[string]bool)\n    var cats []string\n    for _, p := range s.products {\n        if !seen[p.Category] {\n            seen[p.Category] = true\n            cats = append(cats, p.Category)\n        }\n    }\n    return cats\n}\n\nfunc main() {\n    store := NewProductStore()\n    mux := http.NewServeMux()\n    jsonResp := func(w http.ResponseWriter, status int, v interface{}) {\n        w.Header().Set("Content-Type", "application/json")\n        w.WriteHeader(status)\n        json.NewEncoder(w).Encode(v)\n    }\n    mux.HandleFunc("/products/categories", func(w http.ResponseWriter, r *http.Request) {\n        jsonResp(w, 200, store.Categories())\n    })\n    mux.HandleFunc("/products", func(w http.ResponseWriter, r *http.Request) {\n        if r.Method != http.MethodGet {\n            return\n        }\n        q := r.URL.Query()\n        category := q.Get("category")\n        minPrice, _ := strconv.ParseFloat(q.Get("min_price"), 64)\n        maxPrice, _ := strconv.ParseFloat(q.Get("max_price"), 64)\n        page, _ := strconv.Atoi(q.Get("page"))\n        limit, _ := strconv.Atoi(q.Get("limit"))\n        jsonResp(w, 200, store.Filter(category, minPrice, maxPrice, page, limit))\n    })\n    mux.HandleFunc("/products/", func(w http.ResponseWriter, r *http.Request) {\n        path := strings.TrimPrefix(r.URL.Path, "/products/")\n        parts := strings.Split(path, "/")\n        id := parts[0]\n        if len(parts) == 2 && parts[1] == "stock" && r.Method == http.MethodPut {\n            var body struct {\n                Delta int `json:"delta"`\n            }\n            json.NewDecoder(r.Body).Decode(&body)\n            p, err := store.UpdateStock(id, body.Delta)\n            if err != nil {\n                jsonResp(w, 400, map[string]string{"error": err.Error()})\n                return\n            }\n            jsonResp(w, 200, p)\n            return\n        }\n        jsonResp(w, 200, map[string]string{"id": id})\n    })\n    fmt.Println("Product Service запущен на :8082")\n    http.ListenAndServe(":8082", mux)\n}',
      explanation: 'Паттерн фильтрации: функция Filter принимает все критерии и применяет их последовательно. Пагинация через skip/limit — стандартный подход. Отдельный эндпоинт /products/categories демонстрирует агрегационные запросы. Атомарная операция UpdateStock с проверкой инварианта (неотрицательный остаток) внутри мьютека предотвращает race condition.'
    },
    {
      id: 3,
      title: 'API Gateway',
      type: 'practice',
      difficulty: 'hard',
      description: 'Реализуй API Gateway, который проксирует запросы к нескольким микросервисам, добавляет аутентификацию и агрегирует ответы.',
      requirements: [
        'Маршрутизация: /api/users/* -> :8081, /api/products/* -> :8082',
        'Middleware аутентификации: проверка заголовка Authorization: Bearer <token>',
        'Rate limiting: не более 10 запросов в секунду на IP (in-memory)',
        'Логирование каждого запроса: метод, путь, статус, время ответа',
        'Агрегация: GET /api/dashboard — параллельный запрос к users и products, объединение ответов',
        'Health check: GET /health — статус шлюза и доступность бэкендов'
      ],
      expectedOutput: 'GET /api/users (без токена): 401\nGET /api/users (с токеном): проксировано -> :8081\nGET /api/dashboard: {"users_count":3,"products_count":4,"status":"ok"}\nGET /health: {"gateway":"ok","users_service":"up","products_service":"up"}',
      hint: 'httputil.NewSingleHostReverseProxy создаёт прокси к бэкенду. Для rate limiting используй map[string]*rateLimiter с time.Ticker или token bucket. sync.Map потокобезопасна для хранения лимитеров по IP.',
      solution: 'package main\n\nimport (\n    "encoding/json"\n    "fmt"\n    "io"\n    "log"\n    "net/http"\n    "net/http/httputil"\n    "net/url"\n    "strings"\n    "sync"\n    "time"\n)\n\ntype RateLimiter struct {\n    mu       sync.Mutex\n    tokens   int\n    lastFill time.Time\n    rate     int\n}\n\nfunc (rl *RateLimiter) Allow() bool {\n    rl.mu.Lock()\n    defer rl.mu.Unlock()\n    now := time.Now()\n    elapsed := now.Sub(rl.lastFill).Seconds()\n    rl.tokens += int(elapsed * float64(rl.rate))\n    if rl.tokens > rl.rate {\n        rl.tokens = rl.rate\n    }\n    rl.lastFill = now\n    if rl.tokens > 0 {\n        rl.tokens--\n        return true\n    }\n    return false\n}\n\ntype Gateway struct {\n    limiters sync.Map\n    proxies  map[string]*httputil.ReverseProxy\n}\n\nfunc NewGateway() *Gateway {\n    usersURL, _ := url.Parse("http://localhost:8081")\n    productsURL, _ := url.Parse("http://localhost:8082")\n    return &Gateway{\n        proxies: map[string]*httputil.ReverseProxy{\n            "users":    httputil.NewSingleHostReverseProxy(usersURL),\n            "products": httputil.NewSingleHostReverseProxy(productsURL),\n        },\n    }\n}\n\nfunc (g *Gateway) getLimiter(ip string) *RateLimiter {\n    rl, _ := g.limiters.LoadOrStore(ip, &RateLimiter{tokens: 10, lastFill: time.Now(), rate: 10})\n    return rl.(*RateLimiter)\n}\n\nfunc (g *Gateway) authMiddleware(next http.Handler) http.Handler {\n    return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {\n        if r.URL.Path == "/health" {\n            next.ServeHTTP(w, r)\n            return\n        }\n        auth := r.Header.Get("Authorization")\n        if !strings.HasPrefix(auth, "Bearer ") {\n            http.Error(w, `{"error":"unauthorized"}`, http.StatusUnauthorized)\n            return\n        }\n        next.ServeHTTP(w, r)\n    })\n}\n\nfunc (g *Gateway) loggingMiddleware(next http.Handler) http.Handler {\n    return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {\n        start := time.Now()\n        rec := &statusRecorder{ResponseWriter: w, status: 200}\n        next.ServeHTTP(rec, r)\n        log.Printf("%s %s %d %v", r.Method, r.URL.Path, rec.status, time.Since(start))\n    })\n}\n\ntype statusRecorder struct {\n    http.ResponseWriter\n    status int\n}\n\nfunc (r *statusRecorder) WriteHeader(status int) {\n    r.status = status\n    r.ResponseWriter.WriteHeader(status)\n}\n\nfunc (g *Gateway) rateLimitMiddleware(next http.Handler) http.Handler {\n    return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {\n        ip := r.RemoteAddr\n        if idx := strings.LastIndex(ip, ":"); idx != -1 {\n            ip = ip[:idx]\n        }\n        if !g.getLimiter(ip).Allow() {\n            http.Error(w, `{"error":"rate limit exceeded"}`, http.StatusTooManyRequests)\n            return\n        }\n        next.ServeHTTP(w, r)\n    })\n}\n\nfunc checkBackend(url string) string {\n    client := &http.Client{Timeout: 2 * time.Second}\n    resp, err := client.Get(url + "/health")\n    if err != nil || resp.StatusCode >= 500 {\n        return "down"\n    }\n    return "up"\n}\n\nfunc (g *Gateway) ServeHTTP(w http.ResponseWriter, r *http.Request) {\n    w.Header().Set("Content-Type", "application/json")\n    path := r.URL.Path\n    switch {\n    case path == "/health":\n        json.NewEncoder(w).Encode(map[string]string{\n            "gateway":          "ok",\n            "users_service":    checkBackend("http://localhost:8081"),\n            "products_service": checkBackend("http://localhost:8082"),\n        })\n    case path == "/api/dashboard":\n        var wg sync.WaitGroup\n        var usersData, productsData []byte\n        wg.Add(2)\n        go func() {\n            defer wg.Done()\n            resp, err := http.Get("http://localhost:8081/users")\n            if err == nil {\n                usersData, _ = io.ReadAll(resp.Body)\n                resp.Body.Close()\n            }\n        }()\n        go func() {\n            defer wg.Done()\n            resp, err := http.Get("http://localhost:8082/products")\n            if err == nil {\n                productsData, _ = io.ReadAll(resp.Body)\n                resp.Body.Close()\n            }\n        }()\n        wg.Wait()\n        var users, products []interface{}\n        json.Unmarshal(usersData, &users)\n        json.Unmarshal(productsData, &products)\n        json.NewEncoder(w).Encode(map[string]interface{}{\n            "users_count":    len(users),\n            "products_count": len(products),\n            "status":         "ok",\n        })\n    case strings.HasPrefix(path, "/api/users"):\n        r.URL.Path = strings.TrimPrefix(path, "/api")\n        g.proxies["users"].ServeHTTP(w, r)\n    case strings.HasPrefix(path, "/api/products"):\n        r.URL.Path = strings.TrimPrefix(path, "/api")\n        g.proxies["products"].ServeHTTP(w, r)\n    default:\n        http.NotFound(w, r)\n    }\n}\n\nfunc main() {\n    gw := NewGateway()\n    handler := gw.loggingMiddleware(gw.authMiddleware(gw.rateLimitMiddleware(gw)))\n    fmt.Println("API Gateway запущен на :8080")\n    http.ListenAndServe(":8080", handler)\n}',
      explanation: 'API Gateway — централизованная точка входа. httputil.NewSingleHostReverseProxy проксирует запросы к бэкендам, изменяя URL. Цепочка middleware: Logging -> Auth -> RateLimit -> Handler. Token bucket rate limiter: токены накапливаются со временем, расходуются при запросах. Dashboard демонстрирует параллельные запросы к нескольким сервисам через sync.WaitGroup.'
    },
    {
      id: 4,
      title: 'Health Check сервис',
      type: 'practice',
      difficulty: 'easy',
      description: 'Создай сервис проверки работоспособности (health check), который мониторит несколько эндпоинтов и предоставляет агрегированный статус.',
      requirements: [
        'Структура HealthCheck: Name string, URL string, Interval time.Duration, Timeout time.Duration',
        'Структура CheckResult: Name string, Status string (up/down/degraded), Latency time.Duration, LastCheck time.Time, Error string',
        'Фоновые горутины периодически проверяют каждый сервис',
        'GET /health — возвращает статус всех сервисов',
        'GET /health/{name} — статус конкретного сервиса',
        'Если latency > 1s — статус "degraded"'
      ],
      expectedOutput: 'GET /health:\n{\n  "overall": "degraded",\n  "services": [\n    {"name":"users","status":"up","latency_ms":45},\n    {"name":"products","status":"degraded","latency_ms":1200}\n  ]\n}',
      hint: 'Каждая горутина проверки использует time.Ticker. Результаты хранятся в sync.Map или map с mutex. http.Client с Timeout для каждой проверки. overall = "up" если все up, "degraded" если есть degraded, "down" если есть down.',
      solution: 'package main\n\nimport (\n    "encoding/json"\n    "fmt"\n    "net/http"\n    "strings"\n    "sync"\n    "time"\n)\n\ntype HealthCheck struct {\n    Name     string\n    URL      string\n    Interval time.Duration\n    Timeout  time.Duration\n}\n\ntype CheckResult struct {\n    Name      string        `json:"name"`\n    Status    string        `json:"status"`\n    LatencyMs int64         `json:"latency_ms"`\n    LastCheck time.Time     `json:"last_check"`\n    Error     string        `json:"error,omitempty"`\n}\n\ntype HealthMonitor struct {\n    mu      sync.RWMutex\n    results map[string]*CheckResult\n}\n\nfunc NewHealthMonitor() *HealthMonitor {\n    return &HealthMonitor{results: make(map[string]*CheckResult)}\n}\n\nfunc (m *HealthMonitor) check(hc HealthCheck) {\n    client := &http.Client{Timeout: hc.Timeout}\n    start := time.Now()\n    result := &CheckResult{Name: hc.Name, LastCheck: start}\n    resp, err := client.Get(hc.URL)\n    latency := time.Since(start)\n    result.LatencyMs = latency.Milliseconds()\n    if err != nil {\n        result.Status = "down"\n        result.Error = err.Error()\n    } else {\n        resp.Body.Close()\n        if resp.StatusCode >= 500 {\n            result.Status = "down"\n            result.Error = fmt.Sprintf("HTTP %d", resp.StatusCode)\n        } else if latency > time.Second {\n            result.Status = "degraded"\n        } else {\n            result.Status = "up"\n        }\n    }\n    m.mu.Lock()\n    m.results[hc.Name] = result\n    m.mu.Unlock()\n}\n\nfunc (m *HealthMonitor) StartMonitoring(checks []HealthCheck) {\n    for _, hc := range checks {\n        go func(h HealthCheck) {\n            m.check(h)\n            ticker := time.NewTicker(h.Interval)\n            for range ticker.C {\n                m.check(h)\n            }\n        }(hc)\n    }\n}\n\nfunc (m *HealthMonitor) GetAll() (string, []*CheckResult) {\n    m.mu.RLock()\n    defer m.mu.RUnlock()\n    var results []*CheckResult\n    overall := "up"\n    for _, r := range m.results {\n        results = append(results, r)\n        if r.Status == "down" {\n            overall = "down"\n        } else if r.Status == "degraded" && overall != "down" {\n            overall = "degraded"\n        }\n    }\n    return overall, results\n}\n\nfunc (m *HealthMonitor) GetByName(name string) (*CheckResult, bool) {\n    m.mu.RLock()\n    defer m.mu.RUnlock()\n    r, ok := m.results[name]\n    return r, ok\n}\n\nfunc main() {\n    monitor := NewHealthMonitor()\n    checks := []HealthCheck{\n        {Name: "users", URL: "http://localhost:8081/health", Interval: 10 * time.Second, Timeout: 3 * time.Second},\n        {Name: "products", URL: "http://localhost:8082/health", Interval: 15 * time.Second, Timeout: 3 * time.Second},\n        {Name: "google", URL: "https://google.com", Interval: 30 * time.Second, Timeout: 5 * time.Second},\n    }\n    monitor.StartMonitoring(checks)\n    time.Sleep(500 * time.Millisecond)\n    mux := http.NewServeMux()\n    mux.HandleFunc("/health", func(w http.ResponseWriter, r *http.Request) {\n        name := strings.TrimPrefix(r.URL.Path, "/health/")\n        if name != "" && name != r.URL.Path {\n            result, ok := monitor.GetByName(name)\n            if !ok {\n                http.Error(w, "не найден", 404)\n                return\n            }\n            w.Header().Set("Content-Type", "application/json")\n            json.NewEncoder(w).Encode(result)\n            return\n        }\n        overall, results := monitor.GetAll()\n        w.Header().Set("Content-Type", "application/json")\n        json.NewEncoder(w).Encode(map[string]interface{}{\n            "overall":  overall,\n            "services": results,\n        })\n    })\n    fmt.Println("Health Check Service запущен на :8083")\n    http.ListenAndServe(":8083", mux)\n}',
      explanation: 'Каждый сервис мониторится в отдельной горутине с time.Ticker. Первоначальная проверка до запуска тикера обеспечивает наличие данных при первом запросе. Общий статус вычисляется в GetAll с понижающей логикой: down > degraded > up. RWMutex оптимален — health endpoint читается часто, обновляется редко.'
    },
    {
      id: 5,
      title: 'Конфигурационный сервис',
      type: 'practice',
      difficulty: 'medium',
      description: 'Создай централизованный сервис конфигурации с поддержкой пространств имён, версионирования и уведомлений об изменениях через long polling.',
      requirements: [
        'Структура Config: Namespace string, Key string, Value string, Version int, UpdatedAt time.Time',
        'GET /config/{namespace}/{key} — получить значение',
        'PUT /config/{namespace}/{key} — установить значение (версия автоинкрементируется)',
        'GET /config/{namespace} — все ключи пространства имён',
        'GET /config/{namespace}/watch?version=N — long polling: ждать до 30 сек пока version > N',
        'DELETE /config/{namespace}/{key} — удалить ключ'
      ],
      expectedOutput: 'PUT /config/app/db_host: {"version":1,"value":"localhost"}\nPUT /config/app/db_host: {"version":2,"value":"prod-server"}\nGET /config/app/db_host: {"key":"db_host","value":"prod-server","version":2}\nGET /config/app/watch?version=1: возвращает немедленно (version=2 > 1)',
      hint: 'Long polling: при запросе с version=N, проверяй есть ли обновление. Если нет — жди на канале уведомлений с таймаутом 30 сек. При обновлении ключа — отправляй в канал namespace. sync.Cond или chan struct{} для уведомлений.',
      solution: 'package main\n\nimport (\n    "encoding/json"\n    "fmt"\n    "net/http"\n    "strconv"\n    "strings"\n    "sync"\n    "time"\n)\n\ntype ConfigEntry struct {\n    Namespace string    `json:"namespace"`\n    Key       string    `json:"key"`\n    Value     string    `json:"value"`\n    Version   int       `json:"version"`\n    UpdatedAt time.Time `json:"updated_at"`\n}\n\ntype ConfigStore struct {\n    mu       sync.RWMutex\n    data     map[string]map[string]*ConfigEntry\n    watchers map[string][]chan struct{}\n}\n\nfunc NewConfigStore() *ConfigStore {\n    return &ConfigStore{\n        data:     make(map[string]map[string]*ConfigEntry),\n        watchers: make(map[string][]chan struct{}),\n    }\n}\n\nfunc (s *ConfigStore) Set(namespace, key, value string) *ConfigEntry {\n    s.mu.Lock()\n    defer s.mu.Unlock()\n    if s.data[namespace] == nil {\n        s.data[namespace] = make(map[string]*ConfigEntry)\n    }\n    version := 1\n    if existing, ok := s.data[namespace][key]; ok {\n        version = existing.Version + 1\n    }\n    entry := &ConfigEntry{Namespace: namespace, Key: key, Value: value, Version: version, UpdatedAt: time.Now()}\n    s.data[namespace][key] = entry\n    for _, ch := range s.watchers[namespace] {\n        select {\n        case ch <- struct{}{}:\n        default:\n        }\n    }\n    return entry\n}\n\nfunc (s *ConfigStore) Get(namespace, key string) (*ConfigEntry, bool) {\n    s.mu.RLock()\n    defer s.mu.RUnlock()\n    ns, ok := s.data[namespace]\n    if !ok {\n        return nil, false\n    }\n    e, ok := ns[key]\n    return e, ok\n}\n\nfunc (s *ConfigStore) GetNamespace(namespace string) map[string]*ConfigEntry {\n    s.mu.RLock()\n    defer s.mu.RUnlock()\n    result := make(map[string]*ConfigEntry)\n    for k, v := range s.data[namespace] {\n        result[k] = v\n    }\n    return result\n}\n\nfunc (s *ConfigStore) MaxVersion(namespace string) int {\n    s.mu.RLock()\n    defer s.mu.RUnlock()\n    max := 0\n    for _, e := range s.data[namespace] {\n        if e.Version > max {\n            max = e.Version\n        }\n    }\n    return max\n}\n\nfunc (s *ConfigStore) Watch(namespace string) (chan struct{}, func()) {\n    ch := make(chan struct{}, 1)\n    s.mu.Lock()\n    s.watchers[namespace] = append(s.watchers[namespace], ch)\n    s.mu.Unlock()\n    cancel := func() {\n        s.mu.Lock()\n        defer s.mu.Unlock()\n        watchers := s.watchers[namespace]\n        for i, w := range watchers {\n            if w == ch {\n                s.watchers[namespace] = append(watchers[:i], watchers[i+1:]...)\n                break\n            }\n        }\n    }\n    return ch, cancel\n}\n\nfunc (s *ConfigStore) Delete(namespace, key string) bool {\n    s.mu.Lock()\n    defer s.mu.Unlock()\n    if s.data[namespace] == nil {\n        return false\n    }\n    if _, ok := s.data[namespace][key]; !ok {\n        return false\n    }\n    delete(s.data[namespace], key)\n    return true\n}\n\nfunc main() {\n    store := NewConfigStore()\n    mux := http.NewServeMux()\n    respond := func(w http.ResponseWriter, status int, v interface{}) {\n        w.Header().Set("Content-Type", "application/json")\n        w.WriteHeader(status)\n        json.NewEncoder(w).Encode(v)\n    }\n    mux.HandleFunc("/config/", func(w http.ResponseWriter, r *http.Request) {\n        path := strings.TrimPrefix(r.URL.Path, "/config/")\n        parts := strings.Split(path, "/")\n        if len(parts) < 1 {\n            http.Error(w, "invalid path", 400)\n            return\n        }\n        namespace := parts[0]\n        if len(parts) == 1 {\n            respond(w, 200, store.GetNamespace(namespace))\n            return\n        }\n        key := parts[1]\n        if key == "watch" {\n            versionStr := r.URL.Query().Get("version")\n            since, _ := strconv.Atoi(versionStr)\n            if store.MaxVersion(namespace) > since {\n                respond(w, 200, store.GetNamespace(namespace))\n                return\n            }\n            ch, cancel := store.Watch(namespace)\n            defer cancel()\n            select {\n            case <-ch:\n                respond(w, 200, store.GetNamespace(namespace))\n            case <-time.After(30 * time.Second):\n                respond(w, 304, nil)\n            }\n            return\n        }\n        switch r.Method {\n        case http.MethodGet:\n            entry, ok := store.Get(namespace, key)\n            if !ok {\n                respond(w, 404, map[string]string{"error": "не найден"})\n                return\n            }\n            respond(w, 200, entry)\n        case http.MethodPut:\n            var body struct {\n                Value string `json:"value"`\n            }\n            if err := json.NewDecoder(r.Body).Decode(&body); err != nil {\n                respond(w, 400, map[string]string{"error": "неверный формат"})\n                return\n            }\n            entry := store.Set(namespace, key, body.Value)\n            respond(w, 200, entry)\n        case http.MethodDelete:\n            if !store.Delete(namespace, key) {\n                respond(w, 404, map[string]string{"error": "не найден"})\n                return\n            }\n            w.WriteHeader(204)\n        }\n    })\n    fmt.Println("Config Service запущен на :8084")\n    http.ListenAndServe(":8084", mux)\n}',
      explanation: 'Long polling: клиент держит соединение открытым до получения изменения или таймаута. Канал уведомлений (chan struct{}) с буфером 1 предотвращает блокировку при отправке сигнала без слушателей. cancel() функция удаляет watcher при завершении запроса — предотвращает утечку памяти. Версионирование позволяет клиентам запрашивать изменения относительно известной версии.'
    },
    {
      id: 6,
      title: 'Сервис аутентификации',
      type: 'practice',
      difficulty: 'hard',
      description: 'Реализуй сервис аутентификации с JWT токенами, refresh tokens и управлением сессиями.',
      requirements: [
        'POST /auth/register — регистрация (username, password)',
        'POST /auth/login — вход, возвращает access_token (15 мин) и refresh_token (7 дней)',
        'POST /auth/refresh — обновление access_token через refresh_token',
        'POST /auth/logout — инвалидация refresh_token',
        'GET /auth/me — информация о текущем пользователе (требует Authorization: Bearer)',
        'Хэширование паролей (упрощённо через crypto/sha256)',
        'JWT в формате base64(header).base64(payload).signature'
      ],
      expectedOutput: 'POST /auth/register: 201 {"id":"...","username":"alice"}\nPOST /auth/login: 200 {"access_token":"...","refresh_token":"...","expires_in":900}\nGET /auth/me: 200 {"id":"...","username":"alice"}\nPOST /auth/logout: 200 {"message":"выход выполнен"}',
      hint: 'JWT без внешних библиотек: header={"alg":"HS256","typ":"JWT"}, payload={"sub":id,"exp":unixtime,"iat":unixtime}. Подпись = HMAC-SHA256(base64(header)+"."+base64(payload), secret). Храни refresh_tokens в map[token]userID.',
      solution: 'package main\n\nimport (\n    "crypto/hmac"\n    "crypto/sha256"\n    "encoding/base64"\n    "encoding/json"\n    "fmt"\n    "net/http"\n    "strings"\n    "sync"\n    "time"\n)\n\nconst jwtSecret = "super-secret-key-do-not-share"\n\ntype User struct {\n    ID           string `json:"id"`\n    Username     string `json:"username"`\n    PasswordHash string `json:"-"`\n}\n\ntype AuthService struct {\n    mu            sync.RWMutex\n    users         map[string]*User\n    refreshTokens map[string]string\n}\n\nfunc NewAuthService() *AuthService {\n    return &AuthService{\n        users:         make(map[string]*User),\n        refreshTokens: make(map[string]string),\n    }\n}\n\nfunc hashPassword(password string) string {\n    h := sha256.New()\n    h.Write([]byte(password + "salt123"))\n    return fmt.Sprintf("%x", h.Sum(nil))\n}\n\nfunc generateToken(userID string, exp time.Time) string {\n    header := base64.RawURLEncoding.EncodeToString([]byte(`{"alg":"HS256","typ":"JWT"}`))\n    payload, _ := json.Marshal(map[string]interface{}{\n        "sub": userID,\n        "exp": exp.Unix(),\n        "iat": time.Now().Unix(),\n    })\n    payloadEnc := base64.RawURLEncoding.EncodeToString(payload)\n    data := header + "." + payloadEnc\n    mac := hmac.New(sha256.New, []byte(jwtSecret))\n    mac.Write([]byte(data))\n    sig := base64.RawURLEncoding.EncodeToString(mac.Sum(nil))\n    return data + "." + sig\n}\n\nfunc parseToken(token string) (string, bool) {\n    parts := strings.Split(token, ".")\n    if len(parts) != 3 {\n        return "", false\n    }\n    data := parts[0] + "." + parts[1]\n    mac := hmac.New(sha256.New, []byte(jwtSecret))\n    mac.Write([]byte(data))\n    expectedSig := base64.RawURLEncoding.EncodeToString(mac.Sum(nil))\n    if !hmac.Equal([]byte(parts[2]), []byte(expectedSig)) {\n        return "", false\n    }\n    payloadBytes, err := base64.RawURLEncoding.DecodeString(parts[1])\n    if err != nil {\n        return "", false\n    }\n    var claims map[string]interface{}\n    if err := json.Unmarshal(payloadBytes, &claims); err != nil {\n        return "", false\n    }\n    exp, ok := claims["exp"].(float64)\n    if !ok || time.Now().Unix() > int64(exp) {\n        return "", false\n    }\n    sub, _ := claims["sub"].(string)\n    return sub, sub != ""\n}\n\nfunc (s *AuthService) Register(username, password string) (*User, error) {\n    s.mu.Lock()\n    defer s.mu.Unlock()\n    for _, u := range s.users {\n        if u.Username == username {\n            return nil, fmt.Errorf("пользователь уже существует")\n        }\n    }\n    u := &User{\n        ID:           fmt.Sprintf("%x", time.Now().UnixNano()),\n        Username:     username,\n        PasswordHash: hashPassword(password),\n    }\n    s.users[u.ID] = u\n    return u, nil\n}\n\nfunc (s *AuthService) Login(username, password string) (access, refresh string, err error) {\n    s.mu.Lock()\n    defer s.mu.Unlock()\n    for _, u := range s.users {\n        if u.Username == username && u.PasswordHash == hashPassword(password) {\n            access = generateToken(u.ID, time.Now().Add(15*time.Minute))\n            refresh = generateToken(u.ID, time.Now().Add(7*24*time.Hour))\n            s.refreshTokens[refresh] = u.ID\n            return access, refresh, nil\n        }\n    }\n    return "", "", fmt.Errorf("неверные учётные данные")\n}\n\nfunc (s *AuthService) Refresh(refreshToken string) (string, error) {\n    s.mu.Lock()\n    defer s.mu.Unlock()\n    userID, ok := s.refreshTokens[refreshToken]\n    if !ok {\n        return "", fmt.Errorf("недействительный refresh token")\n    }\n    if _, valid := parseToken(refreshToken); !valid {\n        delete(s.refreshTokens, refreshToken)\n        return "", fmt.Errorf("refresh token истёк")\n    }\n    return generateToken(userID, time.Now().Add(15*time.Minute)), nil\n}\n\nfunc (s *AuthService) Logout(refreshToken string) {\n    s.mu.Lock()\n    defer s.mu.Unlock()\n    delete(s.refreshTokens, refreshToken)\n}\n\nfunc (s *AuthService) GetUser(id string) (*User, bool) {\n    s.mu.RLock()\n    defer s.mu.RUnlock()\n    u, ok := s.users[id]\n    return u, ok\n}\n\nfunc main() {\n    svc := NewAuthService()\n    mux := http.NewServeMux()\n    respond := func(w http.ResponseWriter, status int, v interface{}) {\n        w.Header().Set("Content-Type", "application/json")\n        w.WriteHeader(status)\n        json.NewEncoder(w).Encode(v)\n    }\n    mux.HandleFunc("/auth/register", func(w http.ResponseWriter, r *http.Request) {\n        var req struct {\n            Username string `json:"username"`\n            Password string `json:"password"`\n        }\n        json.NewDecoder(r.Body).Decode(&req)\n        u, err := svc.Register(req.Username, req.Password)\n        if err != nil {\n            respond(w, 409, map[string]string{"error": err.Error()})\n            return\n        }\n        respond(w, 201, u)\n    })\n    mux.HandleFunc("/auth/login", func(w http.ResponseWriter, r *http.Request) {\n        var req struct {\n            Username string `json:"username"`\n            Password string `json:"password"`\n        }\n        json.NewDecoder(r.Body).Decode(&req)\n        access, refresh, err := svc.Login(req.Username, req.Password)\n        if err != nil {\n            respond(w, 401, map[string]string{"error": err.Error()})\n            return\n        }\n        respond(w, 200, map[string]interface{}{\n            "access_token":  access,\n            "refresh_token": refresh,\n            "expires_in":    900,\n        })\n    })\n    mux.HandleFunc("/auth/refresh", func(w http.ResponseWriter, r *http.Request) {\n        var req struct {\n            RefreshToken string `json:"refresh_token"`\n        }\n        json.NewDecoder(r.Body).Decode(&req)\n        token, err := svc.Refresh(req.RefreshToken)\n        if err != nil {\n            respond(w, 401, map[string]string{"error": err.Error()})\n            return\n        }\n        respond(w, 200, map[string]string{"access_token": token})\n    })\n    mux.HandleFunc("/auth/logout", func(w http.ResponseWriter, r *http.Request) {\n        var req struct {\n            RefreshToken string `json:"refresh_token"`\n        }\n        json.NewDecoder(r.Body).Decode(&req)\n        svc.Logout(req.RefreshToken)\n        respond(w, 200, map[string]string{"message": "выход выполнен"})\n    })\n    mux.HandleFunc("/auth/me", func(w http.ResponseWriter, r *http.Request) {\n        auth := r.Header.Get("Authorization")\n        if !strings.HasPrefix(auth, "Bearer ") {\n            respond(w, 401, map[string]string{"error": "требуется токен"})\n            return\n        }\n        token := strings.TrimPrefix(auth, "Bearer ")\n        userID, ok := parseToken(token)\n        if !ok {\n            respond(w, 401, map[string]string{"error": "недействительный токен"})\n            return\n        }\n        u, ok := svc.GetUser(userID)\n        if !ok {\n            respond(w, 404, map[string]string{"error": "пользователь не найден"})\n            return\n        }\n        respond(w, 200, u)\n    })\n    fmt.Println("Auth Service запущен на :8085")\n    http.ListenAndServe(":8085", mux)\n}',
      explanation: 'JWT без внешних зависимостей: base64(header).base64(payload).HMAC-SHA256(signature). hmac.Equal для сравнения сигнатур предотвращает timing attacks (в отличие от обычного ==). Refresh token хранится в памяти — в production используется Redis. Пароли хэшируются SHA-256 + соль (в production — bcrypt). Access token короткоживущий (15 мин), refresh долгоживущий (7 дней) — стандартная практика.'
    },
    {
      id: 7,
      title: 'Сервис уведомлений',
      type: 'practice',
      difficulty: 'medium',
      description: 'Реализуй сервис уведомлений с поддержкой нескольких каналов (email, SMS, push), очередью и повторными попытками.',
      requirements: [
        'Структура Notification: ID string, UserID string, Channel string (email/sms/push), Message string, Status string (pending/sent/failed), Attempts int',
        'POST /notifications — создать уведомление',
        'GET /notifications/{userID} — уведомления пользователя',
        'GET /notifications/{userID}/unread — непрочитанные',
        'PUT /notifications/{id}/read — пометить прочитанным',
        'Фоновый worker обрабатывает очередь с имитацией отправки (sleep + random error)',
        'Retry: до 3 попыток с задержкой 1 сек'
      ],
      expectedOutput: 'POST /notifications: 202 {"id":"...","status":"pending"}\nWorker: Отправка email для user1... успешно\nWorker: Отправка sms для user2... ошибка (попытка 1/3)\nGET /notifications/user1: [{"id":"...","status":"sent",...}]',
      hint: 'Очередь уведомлений — буферизованный канал chan *Notification. Worker-горутина читает из канала. При ошибке: увеличивай Attempts, если < 3 — снова отправляй в канал после задержки.',
      solution: 'package main\n\nimport (\n    "encoding/json"\n    "fmt"\n    "math/rand"\n    "net/http"\n    "strings"\n    "sync"\n    "time"\n)\n\ntype Notification struct {\n    ID        string    `json:"id"`\n    UserID    string    `json:"user_id"`\n    Channel   string    `json:"channel"`\n    Message   string    `json:"message"`\n    Status    string    `json:"status"`\n    Attempts  int       `json:"attempts"`\n    Read      bool      `json:"read"`\n    CreatedAt time.Time `json:"created_at"`\n}\n\ntype NotificationService struct {\n    mu     sync.RWMutex\n    store  map[string]*Notification\n    queue  chan *Notification\n}\n\nfunc NewNotificationService() *NotificationService {\n    svc := &NotificationService{\n        store: make(map[string]*Notification),\n        queue: make(chan *Notification, 100),\n    }\n    go svc.worker()\n    return svc\n}\n\nfunc (s *NotificationService) worker() {\n    for n := range s.queue {\n        time.Sleep(100 * time.Millisecond)\n        n.Attempts++\n        success := rand.Float32() > 0.3\n        if success {\n            s.mu.Lock()\n            n.Status = "sent"\n            s.mu.Unlock()\n            fmt.Printf("Worker: Отправка %s для %s... успешно\\n", n.Channel, n.UserID)\n        } else {\n            fmt.Printf("Worker: Отправка %s для %s... ошибка (попытка %d/3)\\n", n.Channel, n.UserID, n.Attempts)\n            if n.Attempts < 3 {\n                go func(notif *Notification) {\n                    time.Sleep(time.Second)\n                    s.queue <- notif\n                }(n)\n            } else {\n                s.mu.Lock()\n                n.Status = "failed"\n                s.mu.Unlock()\n            }\n        }\n    }\n}\n\nfunc (s *NotificationService) Create(n Notification) *Notification {\n    n.ID = fmt.Sprintf("%x", time.Now().UnixNano())\n    n.Status = "pending"\n    n.CreatedAt = time.Now()\n    s.mu.Lock()\n    s.store[n.ID] = &n\n    s.mu.Unlock()\n    s.queue <- &n\n    return &n\n}\n\nfunc (s *NotificationService) GetByUser(userID string, unreadOnly bool) []*Notification {\n    s.mu.RLock()\n    defer s.mu.RUnlock()\n    var result []*Notification\n    for _, n := range s.store {\n        if n.UserID == userID {\n            if unreadOnly && n.Read {\n                continue\n            }\n            result = append(result, n)\n        }\n    }\n    return result\n}\n\nfunc (s *NotificationService) MarkRead(id string) bool {\n    s.mu.Lock()\n    defer s.mu.Unlock()\n    n, ok := s.store[id]\n    if !ok {\n        return false\n    }\n    n.Read = true\n    return true\n}\n\nfunc main() {\n    svc := NewNotificationService()\n    mux := http.NewServeMux()\n    respond := func(w http.ResponseWriter, status int, v interface{}) {\n        w.Header().Set("Content-Type", "application/json")\n        w.WriteHeader(status)\n        json.NewEncoder(w).Encode(v)\n    }\n    mux.HandleFunc("/notifications", func(w http.ResponseWriter, r *http.Request) {\n        if r.Method != http.MethodPost {\n            return\n        }\n        var n Notification\n        json.NewDecoder(r.Body).Decode(&n)\n        created := svc.Create(n)\n        respond(w, 202, created)\n    })\n    mux.HandleFunc("/notifications/", func(w http.ResponseWriter, r *http.Request) {\n        path := strings.TrimPrefix(r.URL.Path, "/notifications/")\n        parts := strings.Split(path, "/")\n        if len(parts) == 2 && parts[1] == "unread" {\n            respond(w, 200, svc.GetByUser(parts[0], true))\n            return\n        }\n        if len(parts) == 2 && parts[1] == "read" && r.Method == http.MethodPut {\n            if !svc.MarkRead(parts[0]) {\n                respond(w, 404, map[string]string{"error": "не найдено"})\n                return\n            }\n            w.WriteHeader(204)\n            return\n        }\n        respond(w, 200, svc.GetByUser(parts[0], false))\n    })\n    fmt.Println("Notification Service запущен на :8086")\n    http.ListenAndServe(":8086", mux)\n}',
      explanation: 'Буферизованный канал chan *Notification — простая очередь задач. Worker-горутина обрабатывает уведомления асинхронно. Retry через рекурсивный запуск горутины с задержкой — простой подход; в production используются exponential backoff и dead letter queue. Статус 202 Accepted сигнализирует клиенту, что запрос принят, но не обработан немедленно.'
    },
    {
      id: 8,
      title: 'Сервис заказов с паттерном Saga',
      type: 'practice',
      difficulty: 'hard',
      description: 'Реализуй сервис заказов с паттерном Saga для распределённых транзакций: резервирование инвентаря, оплата и уведомление.',
      requirements: [
        'Структура Order: ID string, UserID string, Items []OrderItem, Status string, TotalAmount float64',
        'Паттерн Saga: каждый шаг имеет компенсирующую транзакцию',
        'Шаги Saga: 1) Reserve inventory -> компенсация: Release inventory; 2) Process payment -> компенсация: Refund; 3) Send notification',
        'Если любой шаг провалился — откатить предыдущие через компенсации',
        'POST /orders — создать заказ и запустить Saga',
        'GET /orders/{id} — статус заказа и лог шагов Saga'
      ],
      expectedOutput: 'POST /orders:\n  Шаг 1: Резервирование товаров... успешно\n  Шаг 2: Обработка оплаты... успешно\n  Шаг 3: Отправка уведомления... успешно\n  Статус: COMPLETED\n\nПри ошибке оплаты:\n  Шаг 2: Обработка оплаты... ОШИБКА\n  Компенсация: Освобождение товаров\n  Статус: FAILED (rolled back)',
      hint: 'Saga хранит []SagaStep с execute и compensate функциями. При успешном выполнении шага добавляй его в completedSteps. При ошибке — перебирай completedSteps в обратном порядке и вызывай compensate.',
      solution: 'package main\n\nimport (\n    "encoding/json"\n    "fmt"\n    "math/rand"\n    "net/http"\n    "strings"\n    "sync"\n    "time"\n)\n\ntype OrderItem struct {\n    ProductID string  `json:"product_id"`\n    Quantity  int     `json:"quantity"`\n    Price     float64 `json:"price"`\n}\n\ntype SagaLog struct {\n    Step      string `json:"step"`\n    Status    string `json:"status"`\n    Message   string `json:"message"`\n    Timestamp time.Time `json:"timestamp"`\n}\n\ntype Order struct {\n    ID          string      `json:"id"`\n    UserID      string      `json:"user_id"`\n    Items       []OrderItem `json:"items"`\n    Status      string      `json:"status"`\n    TotalAmount float64     `json:"total_amount"`\n    SagaLogs    []SagaLog   `json:"saga_logs"`\n    CreatedAt   time.Time   `json:"created_at"`\n}\n\ntype SagaStep struct {\n    Name        string\n    Execute     func() error\n    Compensate  func()\n}\n\ntype OrderService struct {\n    mu     sync.RWMutex\n    orders map[string]*Order\n}\n\nfunc NewOrderService() *OrderService {\n    return &OrderService{orders: make(map[string]*Order)}\n}\n\nfunc simulateService(name string, failRate float32) error {\n    time.Sleep(50 * time.Millisecond)\n    if rand.Float32() < failRate {\n        return fmt.Errorf("%s: временная ошибка сервиса", name)\n    }\n    return nil\n}\n\nfunc (s *OrderService) runSaga(order *Order) {\n    addLog := func(step, status, msg string) {\n        s.mu.Lock()\n        order.SagaLogs = append(order.SagaLogs, SagaLog{\n            Step: step, Status: status, Message: msg, Timestamp: time.Now(),\n        })\n        s.mu.Unlock()\n        fmt.Printf("  Шаг: %s [%s] %s\\n", step, status, msg)\n    }\n    var completedSteps []SagaStep\n    steps := []SagaStep{\n        {\n            Name: "Резервирование товаров",\n            Execute: func() error { return simulateService("inventory", 0.1) },\n            Compensate: func() {\n                fmt.Println("  Компенсация: Освобождение товаров")\n                addLog("Резервирование товаров", "COMPENSATED", "товары освобождены")\n            },\n        },\n        {\n            Name: "Обработка оплаты",\n            Execute: func() error { return simulateService("payment", 0.2) },\n            Compensate: func() {\n                fmt.Println("  Компенсация: Возврат оплаты")\n                addLog("Обработка оплаты", "COMPENSATED", "оплата возвращена")\n            },\n        },\n        {\n            Name: "Отправка уведомления",\n            Execute: func() error { return simulateService("notification", 0.05) },\n            Compensate: func() {},\n        },\n    }\n    for _, step := range steps {\n        fmt.Printf("  Шаг: %s...\\n", step.Name)\n        if err := step.Execute(); err != nil {\n            addLog(step.Name, "FAILED", err.Error())\n            fmt.Printf("  ОШИБКА: %v\\n", err)\n            for i := len(completedSteps) - 1; i >= 0; i-- {\n                completedSteps[i].Compensate()\n            }\n            s.mu.Lock()\n            order.Status = "FAILED"\n            s.mu.Unlock()\n            return\n        }\n        addLog(step.Name, "SUCCESS", "выполнено успешно")\n        completedSteps = append(completedSteps, step)\n    }\n    s.mu.Lock()\n    order.Status = "COMPLETED"\n    s.mu.Unlock()\n    fmt.Println("  Статус: COMPLETED")\n}\n\nfunc (s *OrderService) CreateOrder(o Order) *Order {\n    o.ID = fmt.Sprintf("%x", time.Now().UnixNano())\n    o.Status = "PROCESSING"\n    o.CreatedAt = time.Now()\n    total := 0.0\n    for _, item := range o.Items {\n        total += item.Price * float64(item.Quantity)\n    }\n    o.TotalAmount = total\n    s.mu.Lock()\n    s.orders[o.ID] = &o\n    s.mu.Unlock()\n    go s.runSaga(&o)\n    return &o\n}\n\nfunc (s *OrderService) GetOrder(id string) (*Order, bool) {\n    s.mu.RLock()\n    defer s.mu.RUnlock()\n    o, ok := s.orders[id]\n    return o, ok\n}\n\nfunc main() {\n    svc := NewOrderService()\n    mux := http.NewServeMux()\n    respond := func(w http.ResponseWriter, status int, v interface{}) {\n        w.Header().Set("Content-Type", "application/json")\n        w.WriteHeader(status)\n        json.NewEncoder(w).Encode(v)\n    }\n    mux.HandleFunc("/orders", func(w http.ResponseWriter, r *http.Request) {\n        if r.Method != http.MethodPost {\n            return\n        }\n        var o Order\n        json.NewDecoder(r.Body).Decode(&o)\n        created := svc.CreateOrder(o)\n        respond(w, 202, created)\n    })\n    mux.HandleFunc("/orders/", func(w http.ResponseWriter, r *http.Request) {\n        id := strings.TrimPrefix(r.URL.Path, "/orders/")\n        o, ok := svc.GetOrder(id)\n        if !ok {\n            respond(w, 404, map[string]string{"error": "заказ не найден"})\n            return\n        }\n        respond(w, 200, o)\n    })\n    fmt.Println("Order Service запущен на :8087")\n    http.ListenAndServe(":8087", mux)\n}',
      explanation: 'Паттерн Saga решает проблему распределённых транзакций без двухфазного коммита (2PC). Каждый шаг имеет бизнес-транзакцию (Execute) и компенсирующую транзакцию (Compensate). completedSteps хранит только успешно выполненные шаги — именно их нужно откатить. Обход completedSteps в обратном порядке обеспечивает правильный порядок откатов (LIFO). Saga выполняется в горутине — HTTP ответ возвращается немедленно (202 Accepted).'
    }
  ]
}
